# Tracking variables in a helper function
def is_prime(n):
    if n <= 1:
        debug(f"is_prime result: False (n={n})", "info")
        return False
    if n <= 3:
        debug(f"is_prime result: True (n={n})", "info")
        return True
    if n % 2 == 0 or n % 3 == 0:
        debug(f"is_prime result: False (n={n})", "info")
        return False

    i = 5
    while i * i <= n:
        debug(f"testing i = {i}", "debug")
        if n % i == 0 or n % (i + 2) == 0:
            debug(f"is_prime result: False (n={n}, divisor={i})", "info")
            return False
        i += 6

    debug(f"is_prime result: True (n={n})", "info")
    return True
